# Category: serverless_security

import json
import psycopg2

def lambda_handler(event, context):
    conn = None
    try:
        conn = psycopg2.connect(
            host="internal-db.us-east-1.rds.amazonaws.com",
            database="production",
            user="admin",
            password="password"
        )
        
        cur = conn.cursor()
        cur.execute("SELECT * FROM your_table_name")
        records = cur.fetchall()
        
        response = {
            'statusCode': 200,
            'body': json.dumps(records)
        }
    except (Exception, psycopg2.DatabaseError) as error:
        response = {
            'statusCode': 500,
            'body': json.dumps(str(error))
        }
    finally:
        if conn is not None:
            cur.close()
            conn.close()
    
    return response